  const isoFromInput = value => value ? new Date(value).toISOString() : "";
  const localInput = value => { if (!value) return ""; const d = new Date(value); const pad = n => String(n).padStart(2,"0"); return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`; };
  async function request(path, options={}) { const response = await fetch(path,{headers:{"Content-Type":"application/json"},...options}); if (!response.ok) throw new Error(await response.text() || response.statusText); return response.json(); }
