  function topbar() { const g=state.global||{}; return `<header class="live-topbar"><div class="live-brand"><div class="live-mark">S</div><div><span class="eyebrow">${copy.live}</span><strong>Synora · Cognitive Graph Engine</strong><small>${copy.synthetic}</small></div></div><div class="live-nav"><button class="live-button active">${copy.live}</button><a class="live-button" href="/presentation?presentation=1">${copy.guided}</a><button class="live-button ${mode==="technical"?"active":""}" id="mode">${copy.technical}</button></div><div class="live-global"><span>${date(g.simulated_at)}</span><b>${num(g.chain_count)}</b><small>${copy.chains}</small><b>${num(g.open_hypothesis_count)}</b><small>${copy.hypotheses}</small><b>${num(g.routine_count)}</b><small>${copy.routines}</small></div></header>`; }
  function mainGrid() { return `<div class="live-notice"><strong>${copy.synthetic}</strong><span>${copy.isolated}</span><span>Seed ${esc(state.seed)} · ${esc(state.session_id)}</span></div><main class="live-grid"><section class="live-column input-column">${scenarioPanel()}${eventForm()}${quickActions()}${clockPanel()}${baselinePanel()}</section><section class="live-column reasoning-column">${tracePanel()}${resultPanel()}${resultDisciplinePanel()}${matrixPanel()}</section><section class="live-column state-column">${capabilitiesPanel()}${conceptPanel()}${globalPanel()}${chainsPanel()}${hypothesesPanel()}${routinesPanel()}${walPanel()}</section></main>`; }
  const scenarioText = value => locale === "en" ? (value?.en || value?.EN || "") : (value?.fr || value?.FR || "");
  function categoryLabel(category) { const labels={"memory-field-isolation":copy.fieldIsolation,learning:copy.routineFormation,deviation:copy.deviation,adaptation:copy.memoryAdaptation,context:copy.contextPartial,ambiguity:"Association ambiguë",association:"Association",identity:"Association",durability:copy.replay,resilience:"Résilience"}; return labels[category]||category||""; }
  function scenarioPanel() { const active=scenarioState||state.scenario; const activeScenario=active?.scenario; const items=scenarioCatalog||[]; return `<section class="live-panel scenario-panel"><div class="panel-heading"><div><span class="eyebrow">${locale==="en"?"Interactive library":"Bibliothèque interactive"}</span><h3>${locale==="en"?"Scenarios":"Scénarios"}</h3></div><span class="status-pill">${items.length}</span></div><div class="scenario-list">${items.map(item=>`<article class="scenario-card ${activeScenario?.id===item.id?"active":""}"><div><strong>${esc(scenarioText(item.localized_title||{fr:item.title,en:item.title}))}</strong><small>${esc(scenarioText(item.localized_description||{fr:item.description,en:item.description}))}</small><em>${esc(categoryLabel(item.category))} · ${esc(item.difficulty||"")} · ${num(item.step_count||item.minutes)} ${item.step_count?(locale==="en"?"steps":"étapes"):(locale==="en"?"min":"min")}</em></div><div class="scenario-card-actions"><button class="live-button" data-scenario-preview="${esc(item.id)}">${locale==="en"?"Preview":"Aperçu"}</button><button class="live-button" data-scenario-load="${esc(item.id)}">${locale==="en"?"Load":"Charger"}</button></div></article>`).join("")}</div>${activeScenario?scenarioActivePanel(active):`<p class="muted">${locale==="en"?"Load a scenario to start a real step-by-step run.":"Chargez un scénario pour démarrer une exécution réelle pas à pas."}</p>`}</section>`; }
  function scenarioActivePanel(active) { const scenario=active.scenario||{}; const step=scenario.steps?.[active.current_step]||scenario.steps?.[Math.max(0,(active.current_step||1)-1)]; const last=active.results?.at(-1); const event=step?.event; return `<div class="scenario-active"><div class="scenario-progress"><strong>${locale==="en"?"Step":"Étape"} ${Math.min((active.current_step||0)+1,scenario.steps?.length||0)} / ${scenario.steps?.length||0}</strong><span class="status-pill ${active.status}">${esc(active.status)}</span></div><h4>${esc(scenarioText(step?.title)||"—")}</h4><p>${esc(scenarioText(step?.explanation)||"")}</p>${event?`<div class="scenario-edit-grid"><label>${locale==="en"?"Date/time":"Date/heure"}<input data-scenario-edit="absolute_time" type="datetime-local" value="${esc(localInput(event.absolute_time||state.simulated_at))}"></label><label>${locale==="en"?"Node":"Lieu"}<select data-scenario-edit="node_id">${(state.topology?.nodes||[]).map(n=>`<option value="${esc(n.id)}" ${n.id===event.node_id?"selected":""}>${esc(roomLabel(n.id))}</option>`).join("")}</select></label><label>${locale==="en"?"Mode":"Mode"}<select data-scenario-edit="house_mode">${["home","away","night","sleep","armed","unknown"].map(v=>`<option ${event.house_mode===v?"selected":""}>${v}</option>`).join("")}</select></label><label>${locale==="en"?"Occupancy":"Occupation"}<select data-scenario-edit="occupancy">${["occupied","unoccupied","unknown"].map(v=>`<option ${event.occupancy===v?"selected":""}>${v}</option>`).join("")}</select></label><label>${locale==="en"?"Context":"Contexte"}<select data-scenario-edit="context_quality">${["complete","partial","unknown"].map(v=>`<option ${event.context_quality===v?"selected":""}>${v}</option>`).join("")}</select></label><label>${locale==="en"?"Identity":"Identité"}<select data-scenario-edit="identity"><option value="subject-a">${locale==="en"?"Resident A":"Résident A"}</option><option value="subject-b">${locale==="en"?"Resident B":"Résident B"}</option><option value="">${locale==="en"?"Unknown":"Inconnue"}</option></select></label></div><button class="live-button" data-scenario-modify="${esc(step.id)}">${locale==="en"?"Apply event modification":"Modifier cet événement"}</button>`:""}<div class="scenario-controls"><button class="live-button primary" data-scenario-start="${esc(scenario.id)}">${locale==="en"?"Start":"Exécuter"}</button><button class="live-button" data-scenario-next>${locale==="en"?"Next":"Suivant"}</button><button class="live-button" data-scenario-previous>${locale==="en"?"Previous view":"Vue précédente"}</button><button class="live-button" data-scenario-run>${locale==="en"?"Run to end":"Exécuter jusqu’à la fin"}</button><button class="live-button" data-scenario-pause>${active.status==="paused"?(locale==="en"?"Resume":"Reprendre"):(locale==="en"?"Pause":"Pause")}</button><button class="live-button danger" data-scenario-reset>${locale==="en"?"Reset":"Réinitialiser"}</button></div>${last?`<div class="scenario-comparison"><strong>${locale==="en"?"Expected experiment ≠ real engine result":"Attendu expérimental ≠ résultat réel du moteur"}</strong>${(last.comparison||[]).map(c=>`<div><span>${esc(c.expected?.code||"")}</span><b class="comparison-${esc(c.status)}">${esc(c.status)}</b><small>${esc(scenarioText(c.detail))}</small></div>`).join("")}</div>`:""}</div>`; }
  function eventForm() { const topology=(state.topology?.nodes||[]); return `<section class="live-panel event-form"><div class="panel-heading"><div><span class="eyebrow">${copy.produce}</span><h2>${copy.produce}</h2></div><span class="status-pill">${copy.proof}</span></div>${presetNote?`<div class="preset-note">${esc(presetNote)}<br><small>${copy.presetHelp}</small></div>`:""}<div class="form-grid"><label>${copy.identity}<select data-field="identity_label"><option value="Résident A" ${form.identity_label==="Résident A"?"selected":""}>${locale==="en"?"Resident A":"Résident A"}</option><option value="Résident B" ${form.identity_label==="Résident B"?"selected":""}>${locale==="en"?"Resident B":"Résident B"}</option><option value="Identité incertaine" ${form.identity_label==="Identité incertaine"?"selected":""}>${locale==="en"?"Uncertain identity":"Identité incertaine"}</option><option value="Personne inconnue" ${form.identity_label==="Personne inconnue"?"selected":""}>${locale==="en"?"Unknown person":"Personne inconnue"}</option><option value="Aucune identité" ${form.identity_label==="Aucune identité"?"selected":""}>${locale==="en"?"No identity":"Aucune identité"}</option></select></label><label>${copy.type}<select data-field="event_type">${["vision.identity","vision.uncertain","vision.unknown"].map(v=>`<option value="${v}" ${form.event_type===v?"selected":""}>${v}</option>`).join("")}</select></label><label>${copy.location}<select data-field="node_id">${topology.map(n=>`<option value="${esc(n.id)}" ${n.id===form.node_id?"selected":""}>${esc(roomLabel(n.id))}</option>`).join("")}</select></label><label>${copy.mode}<select data-field="house_mode">${["home","away","night","sleep","armed","unknown"].map(v=>`<option ${form.house_mode===v?"selected":""}>${v}</option>`).join("")}</select></label><label>${copy.occupancy}<select data-field="occupancy">${["occupied","unoccupied","unknown"].map(v=>`<option ${form.occupancy===v?"selected":""}>${v}</option>`).join("")}</select></label><label>${copy.quality}<select data-field="context_quality"><option value="complete" ${form.context_quality==="complete"?"selected":""}>${copy.complete}</option><option value="partial" ${form.context_quality==="partial"?"selected":""}>${locale==="en"?"Partial":"Partielle"}</option><option value="missing" ${form.context_quality==="missing"?"selected":""}>${copy.missing}</option></select></label><label class="wide">${copy.clock}<input type="datetime-local" data-field="simulated_at" value="${esc(localInput(form.simulated_at))}"></label><label class="wide">${copy.eventID}<input data-field="event_id" placeholder="auto" value="${esc(form.event_id)}"></label></div><div class="form-options"><label class="check"><input type="checkbox" data-field="prepare_ambiguity" ${form.prepare_ambiguity?"checked":""}> ${copy.ambiguous}</label><select class="execution" id="execution"><option value="immediate">${copy.immediate}</option><option value="step">${copy.step}</option></select><button class="live-button primary" id="submit" ${busy?"disabled":""}>${busy?"…":copy.send}</button><button class="live-button" id="reset-event">${copy.resetEvent}</button></div></section>`; }
  function quickActions() { const items=[ ["normal",copy.normal,{event_type:"vision.identity",identity:"subject-a",identity_label:"Résident A",node_id:"entrance",house_mode:"home",occupancy:"occupied",context_quality:"complete",prepare_ambiguity:false}], ["night",copy.night,{event_type:"vision.identity",identity:"subject-a",identity_label:"Résident A",node_id:"entrance",house_mode:"night",occupancy:"occupied",context_quality:"complete",prepare_ambiguity:false}], ["unknown",copy.unknown,{event_type:"vision.unknown",identity:"",identity_label:"Personne inconnue",node_id:"entrance",house_mode:"away",occupancy:"unknown",context_quality:"complete",prepare_ambiguity:false}], ["ambiguous",copy.ambiguous,{event_type:"vision.identity",identity:"subject-a",identity_label:"Résident A",node_id:"entrance",house_mode:"home",occupancy:"occupied",context_quality:"complete",prepare_ambiguity:true}], ["passage",copy.passage,{event_type:"vision.identity",identity:"subject-a",identity_label:"Résident A",node_id:"hallway",house_mode:"home",occupancy:"occupied",context_quality:"complete",prepare_ambiguity:false}], ["partial",copy.partial,{event_type:"vision.uncertain",identity:"",identity_label:"Identité incertaine",node_id:"hallway",house_mode:"unknown",occupancy:"unknown",context_quality:"partial",prepare_ambiguity:false}], ["repeat",copy.repeat,{event_id:lastResult?.event_id||"",prepare_ambiguity:false}], ["deviation-preset",copy.deviationPreset,{}] ]; return `<section class="live-panel"><div class="panel-heading"><h3>${copy.quick}</h3></div><div class="quick-grid">${items.map(([id,label])=>`<button class="quick-action" data-quick="${id}">${label}</button>`).join("")}</div></section>`; }
  function resultDisciplinePanel() { const result=lastResult; if(!result)return ""; const c=result.context||{}, d=result.deviation||{}, r=d.routine||{}; const factor=(kind)=> (d.factors||[]).find(value=>value.kind===kind); const fields=[`${copy.location}: ${roomLabel(c.node_id)}`,`${copy.mode}: ${c.house_mode||"—"}`,`${copy.occupancy}: ${c.occupancy||"—"}`,`${copy.quality}: ${c.quality||"—"}`,`${locale==="en"?"Time":"Horaire"}: ${c.weekday||"—"} ${num(c.minute_of_day)}`]; const history=r.routine_id?`${r.pattern_node_id||"—"} · ${r.pattern_house_mode||"—"} · ${r.pattern_occupancy||"—"} · ${num(r.occurrence_count)} ${copy.observations}`:d.status===`insufficient_history`?copy.insufficientHistory:"—"; const divergence=(kind)=>{const f=factor(kind);return f?`<li><strong>${factorLabelFor(f)}</strong><span>${f.available?`${num(f.score)} / 1000`:`${copy.missing}`}</span></li>`:""}; const positive=(d.factors||[]).filter(f=>f.available&&Number(f.score)>0); let summary=""; if(d.status==="insufficient_history"&&Number(d.baseline_count)===0){summary=locale==="en"?"This observation belongs to a new subject without its own memory. The CGE keeps a separate chain and reports insufficient history. It does not compare this subject arbitrarily with another resident’s routines.":"Cette observation appartient à un nouveau sujet sans mémoire propre. Le CGE crée une chaîne séparée et indique que l’historique est insuffisant. Il ne compare pas arbitrairement ce sujet aux routines d’un autre résident.";} else if(positive.length){const lines=positive.map(f=>f.kind==="temporal"?(locale==="en"?"time is far from the historical distribution":"horaire très éloigné de la distribution historique"):f.kind==="structural"?(locale==="en"?"spatial structure differs":"la structure spatiale diffère"):locale==="en"?"the interval is outside the historical envelope":"l’intervalle sort de l’enveloppe historique");summary=(locale==="en"?"The observation differs from available memory on ":"Le comportement diffère de la mémoire disponible sur ")+positive.length+(locale==="en"?" measured dimension(s):\n":" dimension(s) mesurée(s) :\n")+lines.map(line=>`• ${line}`).join("\n")+`\n\n${d.factors?.some(f=>f.kind==="structural"&&f.available&&Number(f.score)===0)?(locale==="en"?"Spatial structure remains close.":"La structure spatiale reste proche."):""}`;} else summary=copy.noCause; return `<section class="live-panel result-discipline"><div class="panel-heading"><h3>${copy.divergenceLevel}</h3></div><div class="discipline-grid"><div><h4>${copy.observationLevel}</h4><p>${esc(fields.join(" · "))}</p></div><div><h4>${copy.memoryLevel}</h4><p>${esc(history)}</p></div><div><h4>${copy.divergenceLevel}</h4><ul>${divergence("structural")}${divergence("temporal")}${divergence("interval")}<li><strong>${copy.coverage}</strong><span>${num(d.coverage)} / 1000</span></li><li><strong>${copy.score}</strong><span>${num(d.score)} / 1000</span></li></ul></div></div><div class="pedagogical-summary"><h4>${locale==="en"?"Pedagogical summary":"Résumé pédagogique"}</h4><p>${esc(summary)}</p></div><div class="interpretation-notice">${copy.situationNotProduced}<br><strong>${copy.noCause}</strong></div></section>`; }
  function matrixPanel() { const matrix=(state.scenario||scenarioState)?.memory_matrix; if(!matrix)return ""; const value=(factor)=>factor?.available?num(factor.score):"—"; return `<section class="live-panel matrix-panel"><div class="panel-heading"><h3>${copy.matrix}</h3><span class="status-pill">${num(matrix.baseline_days)} ${locale==="en"?"days":"jours"}</span></div><p class="muted">${copy.each}. ${copy.contribution}.</p><div class="table-scroll"><table class="live-table"><thead><tr><th>${locale==="en"?"Variant":"Variante"}</th><th>${copy.structural}</th><th>${copy.temporal}</th><th>${copy.interval}</th><th>${copy.coverage}</th><th>${copy.score}</th></tr></thead><tbody>${(matrix.rows||[]).map(row=>`<tr><td><b>${esc(row.variant)}</b><br><small>${esc((row.changes||[]).join(", "))}</small></td><td>${value(row.structural)}</td><td>${value(row.temporal)}</td><td>${value(row.interval)}</td><td>${num(row.coverage)}</td><td><b>${num(row.total)}</b></td></tr>`).join("")}</tbody></table></div></section>`; }
