  function clockPanel() { return `<section class="live-panel"><div class="panel-heading"><h3>${copy.clock}</h3><strong class="sim-time">${date(state.simulated_at)}</strong></div><div class="clock-buttons"><button class="live-button" data-advance="1">${copy.oneMinute}</button><button class="live-button" data-advance="15">${copy.fifteen}</button><button class="live-button" data-advance="60">${copy.oneHour}</button><button class="live-button" data-advance="1440">${copy.oneDay}</button><button class="live-button" data-advance="10080">${copy.oneWeek}</button></div><div class="custom-clock"><input type="datetime-local" id="custom-clock" value="${esc(localInput(state.simulated_at))}"><button class="live-button" id="set-clock">${copy.custom}</button></div></section>`; }
  function baselinePanel() { return `<section class="live-panel"><div class="panel-heading"><h3>${copy.baseline}</h3></div><p class="muted">${copy.empty} · ${copy.baseline} ${copy.batch7}/${copy.batch30}. ${copy.each}</p><div class="baseline-buttons"><button class="live-button" data-baseline="7" ${busy?"disabled":""}>${copy.batch7}</button><button class="live-button" data-baseline="30" ${busy?"disabled":""}>${copy.batch30}</button><button class="live-button danger" id="reset-session">${copy.resetSession}</button></div><div class="batch-row"><span class="muted">${copy.batch}</span>${[1,3,7,14].map(n=>`<button class="live-button" data-batch="${n}" ${busy?"disabled":""}>${n}</button>`).join("")}${busy?`<button class="live-button danger" id="cancel-batch">${copy.cancel}</button>`:""}</div></section>`; }
  function tracePanel() { const trace=(lastResult?.trace||state.trace||[]); const visible=trace.slice(0,revealed); return `<section class="live-panel trace-panel"><div class="panel-heading"><div><span class="eyebrow">${copy.trace}</span><h2>${copy.trace}</h2></div><span class="status-pill">${lastResult?`${num(trace.length)} étapes`:copy.noResult}</span></div><div class="trace-list">${visible.length?visible.map((step,i)=>`<button class="trace-item ${i===visible.length-1?"current":""}" data-trace="${i}"><span class="trace-number">${i+1}</span><span><b>${traceLabel(step.kind)}</b><small>${date(step.at)} · ${num(step.duration_micros||0)} μs</small></span><span>›</span></button>`).join(""):emptyTrace()}</div>${lastResult&&execution==="step"&&revealed<trace.length?`<button class="live-button primary next-step" id="next-step">${copy.next}</button>`:""}</section>`; }
  function resultPanel() { if(!lastResult)return `<section class="live-panel empty-result"><p>${copy.noResult}</p><div class="interpretation-notice">${copy.noCause}</div></section>`; return `<section class="live-panel result-panel"><div class="context-strip"><span><b>${copy.location}</b>${esc(roomLabel(lastResult.context.node_id))} · ${esc(lastResult.context.zone_id||"—")}</span><span><b>${copy.mode}</b>${esc(lastResult.context.house_mode||"—")}</span><span><b>${copy.occupancy}</b>${esc(lastResult.context.occupancy||"—")}</span><span><b>${copy.quality}</b>${esc(lastResult.context.quality||"—")}</span><span><b>day-part</b>${esc(lastResult.context.day_part||"—")}</span></div><div class="result-head"><h3>${copy.association}</h3><span class="decision ${lastResult.association.decision}">${esc(lastResult.association.decision||"—")}</span></div><div class="result-grid"><div><strong>${copy.score}</strong><b>${num(lastResult.association.best_score)}</b></div><div><strong>${copy.margin}</strong><b>${num(lastResult.association.score_margin)}</b></div><div><strong>${copy.selected}</strong><b class="mono">${esc(lastResult.association.selected_chain_id||"—")}</b></div><div><strong>${copy.created}</strong><b class="mono">${esc(lastResult.association.new_chain_id||"—")}</b></div></div><div class="result-split"><div><h4>${copy.candidates}</h4>${candidateTable(lastResult.association.candidates)}</div><div><h4>${copy.evidence}</h4>${evidenceView(lastResult.evidence)}</div></div>${lastResult.association.decision==="ambiguous"?`<div class="amber-callout">${copy.noChoice}</div>`:""}<div class="result-split"><div><h4>${copy.deviation}</h4>${deviationView(lastResult.deviation)}</div><div><h4>${copy.learning}</h4>${learningView(lastResult.learning)}</div></div><div class="before-after"><span>${copy.selected}: ${esc(lastResult.chain_before?.id||"—")} → ${esc(lastResult.chain_after?.id||"—")}</span><span>rev ${num(lastResult.chain_before?.revision||0)} → ${num(lastResult.chain_after?.revision||0)}</span><span>${copy.observations}: ${num(lastResult.chain_before?.observation_count||0)} → ${num(lastResult.chain_after?.observation_count||0)}</span></div><details><summary>${copy.why}</summary><pre class="json-detail">${esc(JSON.stringify(lastResult,null,2))}</pre></details><div class="interpretation-notice">${copy.situationNotProduced}<br><strong>${copy.noCause}</strong></div></section>`; }
  function reasonLabel(code) { if(code==="time.out_of_window") return copy.outWindow; return code||"—"; }
