  function candidateDecision(candidate) { if(candidate.eligible) return locale==="en"?"Eligible candidate":"Candidat éligible"; const code=candidate.rejection_code||"—"; return mode==="technical"?`${esc(code)} · ${esc(reasonLabel(code))}`:esc(reasonLabel(code)); }
  function candidateTable(candidates=[]) { const outWindow=candidates.some(c=>c.rejection_code==="time.out_of_window"); return candidates.length?`<div class="table-scroll"><table class="live-table"><thead><tr><th>ID</th><th>${copy.score}</th><th>${mode==="technical"?(locale==="en"?"Eligibility / reason":"Éligibilité / motif"):locale==="en"?"Decision":"Décision"}</th><th>Facts</th></tr></thead><tbody>${candidates.map(c=>`<tr><td class="mono">${esc(c.chain_id)}</td><td><b>${num(c.score)}</b></td><td>${candidateDecision(c)}</td><td>${(c.facts||[]).map(f=>`${esc(mode==="technical"?f.code:factLabel(f.code))}=${num(f.score)}`).join(" · ")}</td></tr>`).join("")}</tbody></table></div>${outWindow?`<div class="reason-callout"><b>${copy.outWindow}</b><span>${copy.outWindowDetail}</span></div>`:""}`:`<span class="muted">—</span>`; }
  function evidenceView(e) { const insufficient=e.decision==="insufficient_evidence"&&Number(e.support_score)===0&&Number(e.contradiction_score)===0; if(mode!=="technical"&&insufficient)return `<div class="confidence-callout"><b>${copy.confidenceNotEstablished}</b><span>${copy.evidenceInsufficient}</span></div>`; return `<div class="mini-stat"><b>${esc(e.decision||"—")}</b><span>${copy.support} ${num(e.support_score)} · ${copy.contradiction} ${num(e.contradiction_score)} · ${copy.margin.toLowerCase()} ${num(e.decision_margin)}</span></div>${mode==="technical"?`<div class="fact-list">${(e.facts||[]).map(f=>`<div><span>${esc(f.code)}</span><b>${esc(f.side)} ${num(f.score)}</b></div>`).join("")}</div>`:""}`; }
