  function deviationView(d) { if(!d.attempted)return `<div class="deviation-state"><b>${copy.noAssessment}</b></div>`; if(d.status==="insufficient_history")return `<div class="deviation-state"><b>${copy.insufficientHistory}</b><span>${esc(d.status)}</span></div>`; const zero=(d.status==="evaluated"||d.status==="partial")&&Number(d.score)===0&&Number(d.coverage)>0; return `<div class="deviation-state"><b>${zero?copy.alignedZero:copy.deviation}</b>${zero?`<span>${copy.alignedZeroDetail}</span>`:""}</div><div class="deviation-score"><b>${num(d.score)}</b><span>/ 1000 · ${esc(d.band)} · ${copy.coverage} ${num(d.coverage)}</span></div><div class="factor-list">${(d.factors||[]).map(f=>`<div><span>${esc(factorLabelFor(f))}</span><i style="--factor:${Math.max(3,Number(f.score)/10)}%"></i><b>${num(f.score)}</b></div>`).join("")}</div>${unexpectedZero(d)?`<div class="diagnostic-alert"><b>${copy.diagnostic}</b><span>${diagnosticDetails(d)}</span></div>`:""}`; }
  function learningView(l) { return `<div class="mini-stat"><b>${num(l.occurrence_count_before)} → ${num(l.occurrence_count_after)}</b><span>${num(l.routine_count_before)} → ${num(l.routine_count_after)} routines · ${copy.learning}</span></div>`; }
  function globalPanel() { const g=state.global||{}; return `<section class="live-panel global-panel"><div class="panel-heading"><h3>${copy.chainState}</h3><span class="status-pill good">${esc(g.coordinator_state)}</span></div><div class="global-metrics"><div><b>${num(g.chain_count)}</b><span>${copy.chains}</span></div><div><b>${num(g.open_hypothesis_count)}</b><span>${copy.hypotheses}</span></div><div><b>${num(g.routine_count)}</b><span>${copy.routines}</span></div><div><b>${num(g.observation_count)}</b><span>${copy.occurrences}</span></div><div><b>${num(g.journal_sequence)}</b><span>${copy.wal}</span></div></div><div class="safety-badge">${copy.isolated}<br><strong>${copy.isolated.includes("aucune")?"Aucune action de sécurité":"No security action"}</strong></div></section>`; }
