  function hypothesesPanel() { return `<section class="live-panel"><div class="panel-heading"><h3>${copy.hypothesesView}</h3><span>${num(state.hypotheses?.length)}</span></div><p class="muted">${copy.associationHypothesesHelp}</p>${(state.hypotheses||[]).map(h=>`<details class="hypothesis-card"><summary><b>${esc(val(h,"id","ID"))}</b><span>${esc(val(h,"status","Status"))} · rev ${num(val(h,"revision","Revision"))}</span></summary><p>${esc(val(h,"family","Family"))} · ${copy.noChoice}</p></details>`).join("")||`<span class="muted">${copy.noResult}</span>`}</section>`; }
