  function technicalTemporal(result) { const c=result.context||{}, d=result.deviation||{}, r=d.routine||{}; return `<details class="technical-time" open><summary>${copy.technical} · ${copy.observed} / ${copy.routineHistory}</summary><div class="technical-grid"><div><b>ObservedAt</b><span>${esc(c.observed_at||"—")}</span><b>Timezone</b><span>${esc(c.timezone||"—")}</span><b>Weekday</b><span>${esc(c.weekday||"—")}</span><b>MinuteOfDay</b><span>${num(c.minute_of_day)}</span><b>TimeBucket</b><span>${num(c.time_bucket)}</span><b>DayPart</b><span>${esc(c.day_part||"—")}</span><b>HouseMode</b><span>${esc(c.house_mode||"—")}</span><b>Occupancy</b><span>${esc(c.occupancy||"—")}</span><b>ContextQuality</b><span>${esc(c.quality||"—")}</span></div><div><b>RoutineID</b><span class="mono">${esc(r.routine_id||d.routine_id||"—")}</span><b>TemporalBins</b><span>${(r.temporal_bins||[]).map(b=>`${esc(b.weekday)}/${num(b.time_bucket)}×${num(b.count)}`).join(" · ")||"—"}</span><b>LastSeenAt</b><span>${esc(r.last_seen_at||"—")}</span><b>IntervalStatistics</b><span>${r.interval_statistics?JSON.stringify(r.interval_statistics):"—"}</span></div></div></details>`; }
